// User types
/**
 * Represents a user in the system.
 * Contains user identification, authentication details, and workspace preferences.
 */
export interface User {
  /** Unique identifier for the user */
  id: string;

  /** User's email address used for authentication and communication */
  email: string;

  /** Display name of the user */
  name: string;

  /** Flag indicating whether the user has super admin privileges */
  isSuperAdmin: boolean;

  /** ID of the last workspace the user accessed, or null if none */
  lastWorkspaceId: string | null;

  /** Timestamp when the user account was created */
  createdAt: Date;

  /** Timestamp when the user account was last updated */
  updatedAt: Date;
}

